export function removeDuplicates(originalArray) {
    const uniqueArray = [];
    const seen = new Set();
    originalArray.forEach((item) => {
        const uniqueIdentifier = item.txid + item.outputIndex;
        if (!seen.has(uniqueIdentifier)) {
            seen.add(uniqueIdentifier);
            uniqueArray.push(item);
        }
    });
    return uniqueArray;
}
